import{Ct as e,Dt as t,at as n,ct as r,dt as i,lt as a,q as o}from"./chunks/framework.BVmwMUcr.js";var s=JSON.parse(`{"title":"Transferring to Electrical Engineering (2026)","description":"Experience sharing on transferring to SCUT's School of Electric Power (Electrical Engineering and Its Automation), including interview preparation, common questions, and answer strategies","frontmatter":{"lang":"en-US","title":"Transferring to Electrical Engineering (2026)","description":"Experience sharing on transferring to SCUT's School of Electric Power (Electrical Engineering and Its Automation), including interview preparation, common questions, and answer strategies","date":"2026-07-16T00:00:00.000Z","author":"Cui","sidebarDepth":2,"llm_translated":true},"headers":[],"relativePath":"en/learn/curricular/transfer_major_electrical_2026.md","filePath":"en/learn/curricular/transfer_major_electrical_2026.md","lastUpdated":1784829332000}`),c={name:`en/learn/curricular/transfer_major_electrical_2026.md`};function l(o,s,c,l,u,d){let f=t(`PdfViewer`);return e(),r(`div`,null,[s[0]||=a(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/curricular/transfer_major_electrical_2026.md for this page in Markdown format</div><h1 id="transferring-to-electrical-engineering-experience-sharing" tabindex="-1">Transferring to Electrical Engineering - Experience Sharing <a class="header-anchor" href="#transferring-to-electrical-engineering-experience-sharing" aria-label="Permalink to “Transferring to Electrical Engineering - Experience Sharing”">​</a></h1><p>Author: Cui</p><hr><h2 id="i-opening-thoughts" tabindex="-1">I. Opening Thoughts <a class="header-anchor" href="#i-opening-thoughts" aria-label="Permalink to “I. Opening Thoughts”">​</a></h2><p>Transferring majors is really not as hard as you imagine.</p><p>During the interview, just be confident and natural. Don&#39;t keep thinking you&#39;re not good enough. What the teachers truly want to see is your genuine self, and whether you really want to study this field.</p><p>I&#39;m actually quite an introverted, timid person myself. I was nervous before the interview too, always worried I&#39;d be asked questions I couldn&#39;t answer. But when I actually got there, I found the teachers weren&#39;t as tough as I&#39;d imagined. It was actually my most relaxed interview -- most of the time, normal conversation was all it took.</p><p>Of course, your weighted average is still very important. Especially at SCUT, I believe hard work really pays off. I&#39;m actually a very ordinary person -- I barely made the cutoff for admission, no talent halo. After starting university, it&#39;s been my own gradual effort and accumulation that got me where I am today.</p><p>So if you&#39;re struggling, anxious, or feeling like you&#39;re not good enough, there&#39;s really no need to be so hard on yourself. Many things, if you take them seriously and persist, will gradually yield results.</p><h2 id="ii-quick-overview-of-school-of-electric-power-transfer-rules" tabindex="-1">II. Quick Overview of School of Electric Power Transfer Rules <a class="header-anchor" href="#ii-quick-overview-of-school-of-electric-power-transfer-rules" aria-label="Permalink to “II. Quick Overview of School of Electric Power Transfer Rules”">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Details</th></tr></thead><tbody><tr><td>Threshold</td><td>No failed required courses, Advanced Math ≥ 80; does not accept those with monochromatic color recognition deficiency</td></tr><tr><td>Assessment</td><td>Interview only, no written exam</td></tr><tr><td>Interview Format</td><td>5-minute PPT personal statement</td></tr><tr><td>Key Points</td><td>Academic status (weighted average, math scores, linear algebra), research/competition experience, subject awareness, personal potential, future plans</td></tr><tr><td>Bonus Points</td><td>Strong university English scores preferred</td></tr></tbody></table><h2 id="iii-interview-ppt-preparation-tips" tabindex="-1">III. Interview PPT Preparation Tips <a class="header-anchor" href="#iii-interview-ppt-preparation-tips" aria-label="Permalink to “III. Interview PPT Preparation Tips”">​</a></h2><p>Your PPT should include these sections:</p><ol><li><strong>Academic Status</strong> (most important) -- Show weighted average, math scores, linear algebra scores</li><li><strong>Research/Competition Experience</strong> (if any) -- Math competitions, mathematical modeling, etc.</li><li><strong>Subject Awareness</strong> -- Understanding of Electrical Engineering, why you want to transfer</li><li><strong>Personal Potential</strong> -- Math/physics foundation, learning ability, resilience</li><li><strong>Future Plans</strong> -- Study plan after transfer, development direction</li></ol><blockquote><p>Make the PPT yourself. Keep content truthful -- no need for fancy templates. Interviewers may ask &quot;Did you make this PPT yourself?&quot; -- you need to be able to answer yes.</p></blockquote><h2 id="iv-common-interview-questions-and-answer-strategies" tabindex="-1">IV. Common Interview Questions and Answer Strategies <a class="header-anchor" href="#iv-common-interview-questions-and-answer-strategies" aria-label="Permalink to “IV. Common Interview Questions and Answer Strategies”">​</a></h2><p>The following is compiled from the interview experiences of several successful Electrical Engineering transfer students, organized by category for reference.</p><h3 id="_4-1-subject-knowledge" tabindex="-1">4.1 Subject Knowledge <a class="header-anchor" href="#_4-1-subject-knowledge" aria-label="Permalink to “4.1 Subject Knowledge”">​</a></h3><p><strong>Q: What is the relationship between Energy Chemical Engineering and Electrical Engineering?</strong></p><p>Energy Chemical Engineering mainly studies energy production and storage (e.g., hydrogen energy, lithium battery materials), while Electrical Engineering studies power transmission, dispatch, and grid integration. They&#39;re not simply upstream/downstream -- they&#39;re deeply coupled in areas like energy storage and electricity-hydrogen coordination. For example, electrolytic water hydrogen production needs chemical engineering to optimize reaction efficiency and electrical engineering to match fluctuating power sources.</p><p><strong>Q: Why transfer to Electrical Engineering instead of staying in Chemical Engineering?</strong></p><p>Because I want to participate in the energy transition from a system level. Chemical Engineering focuses more on energy production and storage, while Electrical Engineering is the key link where new energy actually lands -- transmission and dispatch. I want to go deep into this critical link.</p><p><strong>Q: What is your understanding of Electrical Engineering and Its Automation?</strong></p><p>Electrical Engineering revolves around the generation, transmission, distribution, and control of electrical energy. Core areas include power systems, smart grids, new energy generation, and automation control. The biggest feature of this field is that it sits at the key node of energy utilization -- the hub where new energy actually comes online.</p><p><strong>Q: Do you know about SCUT Electrical Engineering&#39;s strengths or advantages?</strong></p><p>SCUT&#39;s Electrical Engineering program has close cooperation with China Southern Power Grid and Guangdong Power Grid. It has outstanding advantages in new energy grid integration, smart grids, and offshore wind power. The school focuses on Greater Bay Area grid construction with deep industry-academia-research integration, providing strong support for student practice and employment.</p><h3 id="_4-2-motivation-and-planning" tabindex="-1">4.2 Motivation and Planning <a class="header-anchor" href="#_4-2-motivation-and-planning" aria-label="Permalink to “4.2 Motivation and Planning”">​</a></h3><p><strong>Q: Why did you choose to transfer to Electrical Engineering?</strong></p><p>I have a strong interest in the power field. My math/physics foundation is solid, and the logical thinking developed through math competitions and mathematical modeling aligns well with Electrical Engineering. Electrical Engineering is a core national energy strategy field aligned with the dual-carbon development direction. I want to go deep in this area.</p><p><strong>Q: Did you consider Electrical Engineering during Gaokao?</strong></p><p>When filling out Gaokao志愿, I listed Electrical Engineering as a key意向 program, but wasn&#39;t admitted due to志愿 gradient and score ranking. After entering my current program, I&#39;ve always followed the Electrical Engineering field. Competitions have further strengthened my determination to study it.</p><p><strong>Q: What&#39;s your study plan after transferring?</strong></p><p>Three steps: Over the break, self-study circuit basics and make up foundation courses. After enrollment, solidly learn core courses. Proactively enter the lab for research and innovation competitions, with the goal of graduate recommendation.</p><p><strong>Q: You&#39;re coming from a different major with no Electrical Engineering foundation. What if you can&#39;t keep up?</strong></p><p>I&#39;ve already previewed circuit fundamentals, have a strong math/physics foundation (high GPA, provincial second prize in math competition), and my learning ability is verified through competitions. After transferring, I&#39;ll prioritize filling in professional foundation courses and actively seek help from seniors and teachers. I won&#39;t fall behind.</p><p><strong>Q: What if you fail to transfer?</strong></p><p>I&#39;ll accept it gracefully, continue maintaining good grades in my current major, self-study Electrical Engineering basics, and try again at the next opportunity.</p><h3 id="_4-3-competition-experience" tabindex="-1">4.3 Competition Experience <a class="header-anchor" href="#_4-3-competition-experience" aria-label="Permalink to “4.3 Competition Experience”">​</a></h3><p><strong>Q: What difficulties did you encounter in the math competition?</strong></p><p>(Recommended to use the STAR framework.)</p><p>Poor initial planning left me behind schedule. After National Day, I started an intensive突击. The hardest parts were triple integrals and curve/surface integrals. I devoted myself fully every day, discussed with classmates, and broke down the难点. Eventually I earned the provincial second prize. This experience trained my self-discipline and resilience.</p><p><strong>Q: What difficulties did you encounter in mathematical modeling?</strong></p><p>Three main types: unfamiliarity with technical tools (Origin/Excel to multi-layer composite charts -- resolved by looking up tutorials on the spot), team communication issues (calmly restating to confirm before revising), and time management. The MCM/ICM experience helped me adapt to learning quickly under pressure.</p><p><strong>Q: What did you gain from the math competition and math modeling respectively?</strong></p><p>The math competition developed my self-study ability, time planning, and perseverance in facing challenges. Math modeling developed my resilience under pressure, teamwork, and problem coordination. All these abilities transfer well to Electrical Engineering study.</p><h3 id="_4-4-handling-weaknesses" tabindex="-1">4.4 Handling Weaknesses <a class="header-anchor" href="#_4-4-handling-weaknesses" aria-label="Permalink to “4.4 Handling Weaknesses”">​</a></h3><p><strong>Q: How did you complete the MCM paper as the writer with low English scores?</strong></p><p>The paper writer&#39;s core job isn&#39;t translation -- it&#39;s logic and technical content. I was responsible for drafting in Chinese, creating charts, and formatting. After machine translation, I proofread terminology sentence by sentence, and teammates reviewed together. I controlled the core content throughout.</p><p><strong>Q: Your CET-4 score isn&#39;t high. Can you keep up with English文献?</strong></p><p>I&#39;m preparing intensively for CET-6 and have completed two rounds of memorization for over 3,000 core vocabulary words. Simultaneously, I&#39;m accumulating Electrical Engineering English terminology, starting with classic review papers for intensive reading. Exam scores aren&#39;t the终点 -- I have the执行力 to build solid academic English.</p><p><strong>Q: What is your biggest weakness?</strong></p><p>Answer honestly with a real shortcoming, but explain how you&#39;re working to improve. The important thing is to show self-awareness and the drive to change.</p><h3 id="_4-5-industry-knowledge" tabindex="-1">4.5 Industry Knowledge <a class="header-anchor" href="#_4-5-industry-knowledge" aria-label="Permalink to “4.5 Industry Knowledge”">​</a></h3><p><strong>Q: What is your understanding of the dual-carbon strategy?</strong></p><p>Carbon peak by 2030, carbon neutrality by 2060. The core is energy transition, and the key hub of that transition is the power system -- wind/solar grid integration, energy storage dispatch, ultra-high voltage transmission, and new power system construction are all core directions of Electrical Engineering.</p><p><strong>Q: What bottleneck technologies does new energy grid integration currently face?</strong></p><p>Three categories: high-end power chips rely on imports; specialized simulation software is dominated by foreign companies; critical sensors and insulation materials lack sufficient domestic production. It&#39;s precisely because of these短板 that the country urgently needs Electrical Engineering professionals.</p><p><strong>Q: Besides joining the grid, what other career paths does Electrical Engineering offer?</strong></p><p>Power generation groups, power design institutes; new energy and energy storage companies (CATL, BYD); industrial automation and control; electric vehicle electronic control and power electronics; pursuing further studies and research.</p><p><strong>Q: What are the future development trends for the Electrical Engineering industry?</strong></p><p>Three major trends: green and low-carbon (wind/solar + new power systems); intelligent digitalization (smart grid upgrades); and自主可控 (overcoming bottleneck technologies, domesticating core equipment).</p><p><strong>Q: What do you think about new energy storage?</strong></p><p>The core role of new energy storage is to solve the intermittency problem of renewable energy -- store excess electricity when available, release it when needed, turning unstable renewables into stable, usable power. The National Energy Administration has clearly indicated new energy storage is a &quot;必须品&quot; component for building new power systems.</p><h3 id="_4-6-other-frequent-questions" tabindex="-1">4.6 Other Frequent Questions <a class="header-anchor" href="#_4-6-other-frequent-questions" aria-label="Permalink to “4.6 Other Frequent Questions”">​</a></h3><p><strong>Q: What&#39;s the connection between Energy Chemical Engineering and Electrical Engineering?</strong></p><p>Chemical Engineering addresses energy storage materials and hydrogen production; Electrical Engineering handles grid integration and dispatch. They&#39;re deeply coupled in energy storage and electricity-hydrogen coordination. A Chemical Engineering background helps understand energy storage device principles, while studying Electrical Engineering can bridge &quot;material → device → system&quot; -- that&#39;s a composite advantage.</p><p><strong>Q: What are your hobbies/interests?</strong></p><p>Answer honestly. For example, if you stick to night running, explain that it gives you more energy, teaches perseverance and relaxation, and is a good way to regulate yourself.</p><p><strong>Q: Did you make the PPT yourself?</strong></p><p>Yes, independently. I found a clean, suitable template online and tailored it to my situation (grades, competition experience, transfer motivation), modifying the layout and filling in content step by step -- all self-polished.</p><h2 id="v-related-resources" tabindex="-1">V. Related Resources <a class="header-anchor" href="#v-related-resources" aria-label="Permalink to “V. Related Resources”">​</a></h2><ul><li><a href="/en/learn/curricular/transfer_major">Major Transfer Overview</a></li><li><a href="/en/learn/curricular/transfer_major_quick">Quick Guide to Major Transfer at SCUT</a></li></ul><h2 id="vi-appendix-interview-ppt-preview" tabindex="-1">VI. Appendix: Interview PPT Preview <a class="header-anchor" href="#vi-appendix-interview-ppt-preview" aria-label="Permalink to “VI. Appendix: Interview PPT Preview”">​</a></h2>`,74),i(f,{src:`/root-assets/transfer_major/ElectricalEngineering_2026/presentation.pdf`}),s[1]||=n(`p`,null,[n(`a`,{href:`/root-assets/transfer_major/ElectricalEngineering_2026/presentation.pptx`},`Download PPT Source File`)],-1)])}var u=o(c,[[`render`,l]]);export{s as __pageData,u as default};